    // (60+ → A → 4.0, 50–59 → B → 3.0, 35–49 → C → 2.0, <35 → F → 0).
    var CBSE_GRADES = {
        "A1": { native: 10, us4: 4.0 },
        "A2": { native: 9, us4: 4.0 },
        "B1": { native: 8, us4: 3.7 },
        "B2": { native: 7, us4: 3.3 },
        "C1": { native: 6, us4: 3.0 },
        "C2": { native: 5, us4: 2.7 },
        "D": { native: 4, us4: 2.0 },
        "E1": { native: 3, us4: 1.0 },
        "E2": { native: 2, us4: 0.7 },
        "F": { native: 0, us4: 0.0 },
    };
