                    country: userCountry || null,
                    state: userState || null,
                    eligible: countryAllowed && !stateBlocked,
                    ineligibility_reason: !countryAllowed ? "country_not_allowed" : (stateBlocked ? "us_state_blocked" : null),
                    entered: !!entry,
