            valid: true,
            referrer_username: username,
            referrer_country: country,
            recommended_tournament_slug: "" + (data.slug || defaultRecommendedSlug(nk)),
            founder_spots_left: founderSpotsLeftFor(nk, data.slug ? "" + data.slug : null),
